solution_code:
#include <iostream>
#include <stdexcept>

void do_work(int code) {
    if (code == 1)
        throw std::runtime_error("connection failed");
}

void logged_call(int code) {
    try {
        do_work(code);
    } catch (const std::exception& e) {
        std::cout << "[LOG] caught: " << e.what() << "\n";
        throw;
    }
}

int main() {
    int code;
    std::cin >> code;

    try {
        logged_call(code);
        std::cout << "ok\n";
    } catch (const std::exception& e) {
        std::cout << "[OUTER] handled: " << e.what() << "\n";
    }

    return 0;
}

