#include <iostream>
#include <stdexcept>
#include <string>

class DerivedError : public std::runtime_error {
public:
    int id;
    DerivedError(const std::string& msg, int i)
        : std::runtime_error(msg), id(i) {}
};

void inner() {
    throw DerivedError("specialized failure", 9);
}

void pass_through() {
    try {
        inner();
    } catch (const std::runtime_error& e) {
        throw; // bare rethrow preserves DerivedError type
    }
}

int main() {
    try {
        pass_through();
    } catch (const DerivedError& e) {
        std::cout << "DerivedError caught: " << e.what() << "\n";
    } catch (const std::runtime_error& e) {
        std::cout << "runtime caught: " << e.what() << "\n";
    }
    return 0;
}
